import React, { useState } from "react"
import Layout from "../components/Layout"
import DealCard from "../components/DealCard"
import dealsData from "../../data/deals.json"

const DealsPage = () => {
  const { deals } = dealsData
  const [filter, setFilter] = useState("all")
  const [search, setSearch] = useState("")

  const categories = ["all", ...new Set(deals.map(d => d.category))]
  
  const filtered = deals.filter(d => {
    const catMatch = filter === "all" || d.category === filter
    const searchMatch = !search || 
      d.name.toLowerCase().includes(search.toLowerCase()) ||
      d.provider.toLowerCase().includes(search.toLowerCase()) ||
      d.tags?.some(t => t.includes(search.toLowerCase()))
    return catMatch && searchMatch
  })

  return (
    <Layout>
      <h1 style={{ color: "#e0e0e0", fontSize: "1.8rem", marginBottom: "0.5rem" }}>All Deals</h1>
      <p style={{ color: "#888", marginBottom: "1.5rem" }}>{deals.length} deals across {categories.length - 1} categories</p>

      {/* Filters */}
      <div style={{ display: "flex", gap: "0.8rem", marginBottom: "1rem", flexWrap: "wrap" }}>
        {categories.map(cat => (
          <button key={cat} onClick={() => setFilter(cat)} style={{
            padding: "0.4rem 1rem", borderRadius: 20, border: "none", cursor: "pointer",
            background: filter === cat ? "#10b981" : "#1a1a1a",
            color: filter === cat ? "#000" : "#aaa",
            fontSize: "0.8rem", fontWeight: 600, textTransform: "capitalize",
          }}>
            {cat === "all" ? "All" : cat.replace("-", " ")}
          </button>
        ))}
      </div>

      {/* Search */}
      <input
        type="text"
        placeholder="Search deals, providers, tags..."
        value={search}
        onChange={e => setSearch(e.target.value)}
        style={{
          width: "100%", maxWidth: 400, padding: "0.6rem 1rem", borderRadius: 8,
          background: "#1a1a1a", border: "1px solid #333", color: "#e0e0e0",
          fontSize: "0.85rem", marginBottom: "1.5rem", outline: "none",
        }}
      />

      {/* Grid */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: "1.5rem" }}>
        {filtered.map(d => <DealCard key={d.id} deal={d} />)}
      </div>

      {filtered.length === 0 && (
        <p style={{ color: "#666", textAlign: "center", padding: "3rem" }}>No deals match your filters.</p>
      )}
    </Layout>
  )
}

export const Head = () => (
  <>
    <title>All Deals — DevBundles</title>
    <meta name="description" content="Browse all verified deals on VPS, GPU, domains, storage, and AI APIs for solo developers." />
  </>
)

export default DealsPage
